patch:
--- a/multiplexer.sv
+++ b/multiplexer.sv
@@ -1,10 +1,10 @@
 module mux_8to1(
   input [7:0] data_in,
   input [2:0] select,
   output reg out
 );
   always @(*) begin
     out = data_in[select];
   end
 endmodule

 module processor(
   input [7:0] input_bus,
   input [2:0] sel,
-  output [7:0] output_bus
+  output output_bus
 );
-  mux_8to1 mux(.data_in(input_bus[7:0]), .select(sel), .out(output_bus[7:0]));
+  mux_8to1 mux(.data_in(input_bus[7:0]), .select(sel), .out(output_bus));
 endmodule

before_code:
module mux_8to1(
  input [7:0] data_in,
  input [2:0] select,
  output reg out
);
  always @(*) begin
    out = data_in[select];
  end
endmodule

module processor(
  input [7:0] input_bus,
  input [2:0] sel,
  output [7:0] output_bus
);
  mux_8to1 mux(.data_in(input_bus[7:0]), .select(sel), .out(output_bus[7:0]));
endmodule

after_code:
module mux_8to1(
  input [7:0] data_in,
  input [2:0] select,
  output reg out
);
  always @(*) begin
    out = data_in[select];
  end
endmodule

module processor(
  input [7:0] input_bus,
  input [2:0] sel,
  output output_bus
);
  mux_8to1 mux(.data_in(input_bus[7:0]), .select(sel), .out(output_bus));
endmodule
